+int main(int argc, char* argv[])
+{
+  ros::init(argc, argv, "phidgets_high_speed_encoder");
+  ros::NodeHandle n;
+  ros::NodeHandle nh("~");
+  int serial_number = -1;
+  nh.getParam("serial", serial_number);
+  std::string name = "encoder";
+  nh.getParam("name", name);
+  if (serial_number == -1)
+  {
+    nh.getParam("serial_number", serial_number);
+  }
+  std::string topic_path = "phidgets/";
+  nh.getParam("topic_path", topic_path);
+
+  int frequency = 30;
+  nh.getParam("frequency", frequency);
+
+  if (attach(phid, serial_number))
+  {
+    display_properties(phid);
+
+    const int buffer_length = 100;
+    std::string topic_name = topic_path + name;
+    if (serial_number > -1)
+    {
+      char ser[10];
+      sprintf(ser, "%d", serial_number);
+      topic_name += "/";
+      topic_name += ser;
+    }
+    encoder_pub =
+      n.advertise<phidgets_high_speed_encoder::encoder_params>(topic_name,
+          buffer_length);
+    ros::Rate loop_rate(frequency);
+
+    initialised = true;
+
+    while (ros::ok())
+    {
+      ros::spinOnce();
+      loop_rate.sleep();
+    }
+
+    disconnect(phid);
+  }
+  return 0;
+}
